import '../core/utils/validators.dart';
class LeaderboardModel { final int rank,totalPoints,predictionCount,correctScoreCount,correctResultCount,scorerPoints; final String name; LeaderboardModel({required this.rank,required this.name,required this.totalPoints,this.predictionCount=0,this.correctScoreCount=0,this.correctResultCount=0,this.scorerPoints=0}); factory LeaderboardModel.fromMap(Map<String,dynamic> m)=>LeaderboardModel(rank:int.tryParse('${m['rank']??0}')??0,name:_name(m),totalPoints:int.tryParse('${m['total_points']??m['points']??0}')??0,predictionCount:int.tryParse('${m['prediction_count']??0}')??0,correctScoreCount:int.tryParse('${m['correct_score_count']??0}')??0,correctResultCount:int.tryParse('${m['correct_result_count']??0}')??0,scorerPoints:int.tryParse('${m['scorer_points']??0}')??0); static String _name(Map<String,dynamic> m){final n=(m['full_name']??m['display_name']??'').toString(); if(n.isNotEmpty)return n; final e=(m['email']??'').toString(); if(e.contains('@'))return e.split('@').first; return Validators.maskMobile(m['mobile_number']?.toString()).isEmpty?'Player':Validators.maskMobile(m['mobile_number']?.toString());}}
